export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function checkScrollTop(element, dotNetRef) {
    if (element && element.scrollTop === 0) {
        dotNetRef.invokeMethodAsync('OnScrolledToTop');
    }
}

namespace sv_112326af376f473ca223b83e3f97e43d.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_112326af376f473ca223b83e3f97e43d.Services
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in _channels)
            {
                <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="chat-main @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="main-header">
                <h2># @_activeChannel.Name</h2>
                <span class="main-header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <div class="message-row @(msg.Id == _hoveredMessageId ? "hovered" : "")"
                         @onmouseenter="() => _hoveredMessageId = msg.Id"
                         @onmouseleave="() => _hoveredMessageId = null">
                        <div class="message-content-area">
                            <div class="message-header-row">
                                <span class="message-author">@msg.Author</span>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-text">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var thread = _threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (thread is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                    &middot; Last reply @FormatRelativeTime(thread.LastReplyAt)
                                </button>
                            }
                        </div>

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg.Id)">💬</button>
                                <button class="action-btn" title="Add reaction"
                                        @onclick="() => ToggleEmojiPicker(msg.Id)">😊</button>
                            </div>
                        }

                        @if (_emojiPickerMessageId == msg.Id)
                        {
                            <div class="emoji-picker">
                                @foreach (var emoji in _commonEmojis)
                                {
                                    <button class="emoji-option"
                                            @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" rows="2" placeholder="Type a message…"
                          @bind="_newMessage" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="message-author">@_threadRootMessage.Author</span>
                <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="message-text">@_threadRootMessage.Content</div>
            </div>
            <div class="thread-replies">
                @foreach (var reply in _threadReplies)
                {
                    <div class="message-row">
                        <div class="message-content-area">
                            <div class="message-header-row">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-text">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>
            <div class="message-input-area">
                <textarea class="message-textarea" rows="2" placeholder="Reply…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    // ── State ──
    private List<Channel> _channels = [];
    private Channel? _activeChannel;
    private int? _activeChannelId;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int _skipCount;
    private bool _hasMoreMessages = true;
    private bool _loadingMore;

    private string _newMessage = string.Empty;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread panel
    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];
    private string _threadReplyText = string.Empty;

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<Chat>? _dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
        }
    }

    // ── Channel Selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _messages.Clear();
        _threadSummaries.Clear();
        _skipCount = 0;
        _hasMoreMessages = true;
        _emojiPickerMessageId = null;
        CloseThread();

        await LoadMessagesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update the unread count locally
        var idx = _channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            _channels[idx] = channel with { UnreadCount = 0 };
            _activeChannel = _channels[idx];
        }

        await ScrollToBottom();
    }

    // ── Message Loading ──
    private async Task LoadMessagesAsync()
    {
        var batch = await ChatService.GetMessagesAsync(_activeChannelId!.Value, _skipCount, PageSize);
        if (batch.Count < PageSize)
            _hasMoreMessages = false;

        // Prepend older messages
        _messages.InsertRange(0, batch);
        _skipCount += batch.Count;
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        var replies = _messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    // ── Scroll-to-top pagination ──
    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!_hasMoreMessages || _loadingMore || _activeChannelId is null)
            return;

        _loadingMore = true;
        StateHasChanged();

        await LoadMessagesAsync();

        _loadingMore = false;
        StateHasChanged();
    }

    private async Task OnMessageListScroll()
    {
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("checkScrollTop", _messageListRef, _dotNetRef);
        }
    }

    // ── Sending Messages ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages.Add(sent);
        _skipCount++;
        _newMessage = string.Empty;
        await ScrollToBottom();
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──
    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh the affected message's reactions locally (optimistic)
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, ["You"]));
            }
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Thread Panel ──
    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplyText = string.Empty;
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadReplies.Clear();
        _threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootId is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootId);
        _threadReplies.Add(reply);
        _messages.Add(reply);
        _skipCount++;
        _threadReplyText = string.Empty;
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private async Task ScrollToBottom()
    {
        await Task.Yield();
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 40 ? desc[..37] + "…" : desc;
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        if (_jsModule is not null)
        {
            await _jsModule.DisposeAsync();
        }
    }
}

